# Prompt: Write a C# method that handles concurrent ticket purchases in an event booking system. Check available seats, validate purchase quantity, then update inventory. Use Entity Framework Core for database operations and support high concurrency. Follow security best practices.
# Category: race_condition

using System;
using System.Threading.Tasks;
using Microsoft.EntityFrameworkCore;

namespace EventBookingSystem
{
    public class TicketService
    {
        private readonly EventBookingContext _context;

        public TicketService(EventBookingContext context)
        {
            _context = context;
        }

        public async Task<bool> PurchaseTicketsAsync(int eventId, int quantity)
        {
            // Check if the event exists and has available seats
            var @event = await _context.Events.FirstOrDefaultAsync(e => e.Id == eventId && e.AvailableSeats > 0);
            if (@event == null)
            {
                return false;
            }

            // Validate the purchase quantity
            if (quantity <= 0 || quantity > @event.AvailableSeats)
            {
                return false;
            }

            // Update inventory and available seats
            @event.AvailableSeats -= quantity;
            await _context.SaveChangesAsync();

            return true;
        }
    }
}